member.summary:
Start an EditorCoroutine, owned by the calling EditorWindow instance.

using System.Collections;
using Unity.EditorCoroutines.Editor;
using UnityEditor;

public class ExampleWindow : EditorWindow
{
    void OnEnable()
    {
        this.StartCoroutine(CloseWindowDelayed());
    }

    IEnumerator CloseWindowDelayed() //close the window after 1000 frames have elapsed
    {
        int count = 1000;
        while (count > 0)
        {
            yield return null;
        }
        Close();
    }
}

Immediately stop an EditorCoroutine that was started by the calling  instance. This method is safe to call on an already completed EditorCoroutine.

using System.Collections;
using Unity.EditorCoroutines.Editor;
using UnityEditor;
using UnityEngine;

public class ExampleWindow : EditorWindow
{
    EditorCoroutine coroutine;
    void OnEnable()
    {
        coroutine = this.StartCoroutine(CloseWindowDelayed());
    }

    private void OnDisable()
    {
        this.StopCoroutine(coroutine);
    }

    IEnumerator CloseWindowDelayed()
    {
        while (true)
        {
            Debug.Log("Running");
            yield return null;
        }
    }
}

Starts an EditorCoroutine with the specified owner object. 
If the garbage collector collects the owner object, while the resulting coroutine is still executing, the coroutine will stop running.

using System.Collections;
using Unity.EditorCoroutines.Editor;
using UnityEditor;

public class ExampleWindow : EditorWindow
{
    int m_Updates = 0;
    void OnEnable()
    {
        EditorCoroutineUtility.StartCoroutine(CountEditorUpdates(), this);
    }

    IEnumerator CountEditorUpdates()
    {
        while (true)
        {
            ++m_Updates;
            yield return null;
        }
    }
}

This method starts an EditorCoroutine without an owning object. The EditorCoroutine runs until it completes or is canceled using StopCoroutine.

using System.Collections;
using Unity.EditorCoroutines.Editor;
using UnityEditor;
using UnityEngine;

public class ExampleWindow : EditorWindow
{
    void OnEnable()
    {
        EditorCoroutineUtility.StartCoroutineOwnerless(LogTimeSinceStartup());
    }

    IEnumerator LogTimeSinceStartup()
    {
        while (true)
        {
            Debug.LogFormat("Time since startup: {0} s", Time.realtimeSinceStartup);
            yield return null;
        }
    }
}

Immediately stop an EditorCoroutine. This method is safe to call on an already completed EditorCoroutine.

using System.Collections;
using Unity.EditorCoroutines.Editor;
using UnityEditor;
using UnityEngine;

public class ExampleWindow : EditorWindow
{
    EditorCoroutine m_LoggerCoroutine;
    void OnEnable()
    {
        m_LoggerCoroutine = EditorCoroutineUtility.StartCoroutineOwnerless(LogRunning());
    }

    void OnDisable()
    {
        EditorCoroutineUtility.StopCoroutine(m_LoggerCoroutine);
    }

    IEnumerator LogRunning()
    {
        while (true)
        {
            Debug.Log("Running");
            yield return null;
        }
    }
}

Suspends the EditorCoroutine execution for the given amount of seconds, using unscaled time. 
The coroutine execution continues after the specified time has elapsed.

using System.Collections;
using UnityEngine;
using Unity.EditorCoroutines.Editor;
using UnityEditor;

public class MyEditorWindow : EditorWindow
{
    IEnumerator PrintEachSecond()
    {
        var waitForOneSecond = new EditorWaitForSeconds(1.0f);

        while (true)
        {
            yield return waitForOneSecond;
            Debug.Log("Printing each second");
        }
    }
}
